package stringprogram;

public class FirstString {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		String s = "hiii";
		
		System.out.println(s);		
	    
		String s1 = new String ("hello");
	 
		System.out.println(s1);
		
		//charAt() to return the character of the String.
		System.out.println(s1.charAt(2));
		
		//length() to return the length or size of the String.
		System.out.println(s1.length());
		
		//concat () to add on a String to an existing String.
		System.out.println(s1.concat(s));
		
		
		System.out.println(s1);
		
		//contains()to check the charctr is present or not.If present -returns True, if not-returns false
		//System.out.println(s1.contains(s1 ("a")));
		
		
		
		
		
		
		
	}

}
